Ошибка запуска: *`require is not a function`*.

Это значит, что `code_runner` у тебя работает **не в CommonJS-режиме Node.js**, а, скорее всего, в **ESM / sandbox-среде**, где `require(...)` недоступен.

## Что можно сделать

### Вариант 1 — переписать под `import`
Если среда поддерживает ES modules, замени:

```js
const axios=require("axios");
const fs=require("fs");
const path=require("path");
const https=require("https");
```

на:

```js
import axios from "axios";
import fs from "fs";
import path from "path";
import https from "https";
```

И проверь `dirname` — в ESM обычно нет `__dirname`. Нужно так:

```js
import { fileURLToPath } from "url";
const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
```

Тогда путь:

```js
path.join(__dirname, "..", "solana-pay", "config.json")
```

---

### Вариант 2 — если `axios` нельзя импортировать
Во многих раннерах внешние пакеты вообще недоступны. Тогда лучше использовать встроенный `fetch`, если он есть.

Пример замены:

```js
const r = await axios.get("https://api.llama.fi/protocols", {
  headers: { "User-Agent": "OpenClaw/1.0" },
  timeout: 10000
});
```

на:

```js
const res = await fetch("https://api.llama.fi/protocols", {
  headers: { "User-Agent": "OpenClaw/1.0" }
});
const data = await res.json();
```

---

## Исправленная версия под ESM

```js
import fs from "fs";
import path from "path";
import https from "https";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const cfg = JSON.parse(
  fs.readFileSync(path.join(__dirname, "..", "solana-pay", "config.json"), "utf8")
);

const DB = path.join(__dirname, "airdrops.json");

function load() {
  try {
    return JSON.parse(fs.readFileSync(DB, "utf8"));
  } catch {
    return { seen: [], alerts: [] };
  }
}

function save(d) {
  fs.writeFileSync(DB, JSON.stringify(d, null, 2));
}

function notify(m) {
  if (!cfg.telegramBotToken || !cfg.telegramChatId) return;

  const d = JSON.stringify({
    chat_id: cfg.telegramChatId,
    text: m,
    parse_mode: "Markdown"
  });

  const r = https.request(
    {
      hostname: "api.telegram.org",
      path: "/bot" + cfg.telegramBotToken + "/sendMessage",
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Content-Length": Buffer.byteLength(d)
      }
    },
    () => {}
  );

  r.write(d);
  r.end();
}

async function getJson(url) {
  const res = await fetch(url, {
    headers: { "User-Agent": "OpenClaw/1.0" }
  });
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return await res.json();
}

async function scanDefillama() {
  try {
    const data = await getJson("https://api.llama.fi/protocols");
    const protocols = data.filter(
      p => p.chain === "Solana" && p.tvl > 100000 && !p.token
    );

    return protocols.slice(0, 10).map(p => ({
      name: p.name,
      tvl: p.tvl,
      category: p.category,
      url: p.url,
      source: "defillama"
    }));
  } catch (e) {
    console.log("DefiLlama err:", e.message);
    return [];
  }
}

async function scanNewTokens() {
  try {
    const data = await getJson(
      "https://api.coingecko.com/api/v3/coins/markets?vs_currency=usd&category=solana-ecosystem&order=id_asc&per_page=20&page=1"
    );

    return data
      .filter(t => t.market_cap < 50000000)
      .map(t => ({
        name: t.name,
        symbol: t.symbol,
        mcap: t.market_cap,
        price: t.current_price,
        source: "coingecko"
      }));
  } catch (e) {
    console.log("CoinGecko err:", e.message);
    return [];
  }
}

async function scan() {
  console.log("Scanning for airdrop opportunities...");

  const db = load();
  const protos = await scanDefillama();
  const tokens = await scanNewTokens();
  const newFinds = [];

  protos.forEach(p => {
    if (!db.seen.includes(p.name)) {
      db.seen.push(p.name);
      newFinds.push(
        `*${p.name}* (${p.category})\nTVL: $${(p.tvl / 1e6).toFixed(1)}M | No token yet\n${p.url}`
      );
    }
  });

  tokens.forEach(t => {
    if (!db.seen.includes(t.symbol)) {
      db.seen.push(t.symbol);
      newFinds.push(
        `*${t.name}* ($${t.symbol})\nMcap: $${(t.mcap / 1e6).toFixed(1)}M | Price: $${t.price}`
      );
    }
  });

  if (newFinds.length > 0) {
    const msg = "*Airdrop Hunter*\n\n" + newFinds.slice(0, 5).join("\n\n");
    notify(msg);
    console.log("Found", newFinds.length, "new opportunities");
    db.alerts.push({ time: new Date().toISOString(), count: newFinds.length });
  } else {
    console.log("No new finds");
  }

  save(db);
}

scan().catch(e => console.log("ERROR:", e.message));
```

